package Synergech;
import java.util.*;
public class StoringFirst200 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner s=new Scanner(System.in);
		int[] arr=new int[200];
		for(int i=0;i<200;i++)
			arr[i]=i+1;
		for(int i=0;i<200;i++)
			System.out.print(arr[i]+" ");
	}

}
